def read_lines(filepath):
    with open(filepath) as f:
        for line in f:
            yield line.strip()

def filter_comments(lines):
    for line in lines:
        if not line.startswith('#'):
            yield line

def parse_csv(lines):
    for line in lines:
        yield line.split(',')

def get_column(rows, col):
    for row in rows:
        yield row[col]

# Compose the pipeline - nothing executes until iteration
pipeline = get_column(
    parse_csv(
        filter_comments(
            read_lines('data.csv')
        )
    ),
    col=0
)

for value in pipeline:
